  HashBrownDashboard,
  useHashBrownMessageRenderer,
} from "../components/renderers/hashbrown";
const AGENT_ID = "sample_agent";

function ToolBasedPage() {
  return <ToolBasedDashboard agentId={AGENT_ID} />;
}

function A2UIPage() {
  return <A2UIDashboard agentId={AGENT_ID} />;
}

function JsonRenderPage() {
  // json-render falls back to tool-based with a note
  return (
    <div>
      <div className="bg-yellow-50 border border-yellow-200 text-yellow-800 text-sm px-4 py-2 text-center">
        json-render is not yet available as a standalone starter. Showing
        tool-based rendering instead.
      </div>
      <ToolBasedDashboard agentId={AGENT_ID} />
    </div>
  );
}

function HashBrownInner() {
  const RenderMessage = useHashBrownMessageRenderer();
  useShowcaseHooks();
  useShowcaseSuggestions();

  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent={AGENT_ID}>
      <div className="min-h-screen w-full flex items-center justify-center">
        <SalesDashboard agentId={AGENT_ID} />
        <CopilotSidebar
          defaultOpen={true}
          labels={{ modalHeaderTitle: "Sales Dashboard Assistant" }}
          RenderMessage={RenderMessage}
        />
      </div>
    </CopilotKit>
  );
}

function HashBrownPage() {
  return (
    <HashBrownDashboard>
      <HashBrownInner />
    </HashBrownDashboard>
  );
}

export default function Home() {
  const { mode, setMode } = useRenderMode();

  const renderDashboard = () => {
    switch (mode) {
      case "tool-based":
        return <ToolBasedPage />;
      case "a2ui":
        return <A2UIPage />;
      case "json-render":
        return <JsonRenderPage />;
      case "hashbrown":
        return <HashBrownPage />;
      default:
        return <ToolBasedPage />;
    }
  };

  return (
    <div className="h-screen flex flex-col">
      <header className="sticky top-0 z-[60] border-b border-[var(--border)] bg-[var(--card)] px-6 py-3 flex items-center justify-between shrink-0">
        <h1 className="text-sm font-bold text-[var(--foreground)]">
          CopilotKit Sales Dashboard
        </h1>
        <RendererSelector mode={mode} onModeChange={setMode} />
      </header>
      <main className="flex-1 overflow-hidden">{renderDashboard()}</main>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import {
  CopilotRuntime,
  ExperimentalEmptyAdapter,
  copilotRuntimeNextJSAppRouterEndpoint,
} from "@copilotkit/runtime";
import { LangGraphAgent } from "@copilotkit/runtime/langgraph";

const AGENT_URL =
  process.env.AGENT_URL ||
  process.env.LANGGRAPH_DEPLOYMENT_URL ||
  "http://localhost:8123";

if (!process.env.AGENT_URL && !process.env.LANGGRAPH_DEPLOYMENT_URL) {
  console.warn(
    "[copilotkit/route] WARNING: No AGENT_URL or LANGGRAPH_DEPLOYMENT_URL set, falling back to localhost:8123",
  );
}

console.log("[copilotkit/route] Initializing CopilotKit runtime");
console.log(`[copilotkit/route] AGENT_URL: ${AGENT_URL}`);

function createAgent(graphId: string = "sample_agent") {
  return new LangGraphAgent({
    deploymentUrl: AGENT_URL,
    graphId,
    langsmithApiKey: process.env.LANGSMITH_API_KEY || "",
  });
}

const agentNames = [
  "sample_agent",
  "agentic_chat",
  "human_in_the_loop",
  "tool-rendering",
  "gen-ui-tool-based",
  "gen-ui-agent",
  "shared-state-read",
  "shared-state-write",
  "shared-state-streaming",
  "subagents",
  "default",
];

const agents: Record<string, LangGraphAgent> = {};
for (const name of agentNames) {
  agents[name] = createAgent();
}

export const POST = async (req: NextRequest) => {
  try {
    const { handleRequest } = copilotRuntimeNextJSAppRouterEndpoint({
      endpoint: "/api/copilotkit",
      serviceAdapter: new ExperimentalEmptyAdapter(),
      runtime: new CopilotRuntime({
        // @ts-expect-error -- type wrapping mismatch, fixed in source pending release
        agents,
      }),
    });

    return await handleRequest(req);
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : "Unknown error";
    console.error("[copilotkit/route] ERROR:", error);
    return NextResponse.json({ error: message }, { status: 500 });
  }
};

export const GET = async () => {
  let agentStatus = "unknown";
  try {
    const res = await fetch(`${AGENT_URL}/ok`, {
      signal: AbortSignal.timeout(3000),
    });
    agentStatus = res.ok ? "reachable" : `error (${res.status})`;
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e);
    agentStatus = `unreachable (${msg})`;
  }

  const topStatus = agentStatus.startsWith("unreachable") ? "degraded" : "ok";

  return NextResponse.json({
    status: topStatus,
    agent_url: AGENT_URL,
    agent_status: agentStatus,
    env: {
      OPENAI_API_KEY: process.env.OPENAI_API_KEY ? "set" : "NOT SET",
      NODE_ENV: process.env.NODE_ENV,
    },
  });
};

"""
PydanticAI agent with sales todos state, weather/query tools, and HITL scheduling.

Upgraded from proverbs demo to full feature parity with shared tool implementations.
"""

import json
from textwrap import dedent
from typing import Any
from pydantic import BaseModel, Field
from pydantic_ai import Agent, RunContext
from pydantic_ai.ag_ui import StateDeps
from ag_ui.core import EventType, StateSnapshotEvent
from pydantic_ai.models.openai import OpenAIResponsesModel

from dotenv import load_dotenv

from .tools import (
    get_weather_impl,
    query_data_impl,
    manage_sales_todos_impl,
    get_sales_todos_impl,
    schedule_meeting_impl,
    search_flights_impl,
    build_a2ui_operations_from_tool_call,
)
from .tools.types import Flight

load_dotenv()

# =====
# State
# =====
class SalesTodosState(BaseModel):
    """Sales pipeline todos managed by the agent."""
    todos: list[dict[str, Any]] = Field(
        default_factory=list,
        description="The list of sales pipeline todos",
    )

# =====
# Agent
# =====
agent = Agent(
    model=OpenAIResponsesModel("gpt-4.1-mini"),
    deps_type=StateDeps[SalesTodosState],
    system_prompt=dedent("""
        You are a helpful sales assistant that helps manage a sales pipeline.

        The user has a list of sales todos that you can help them manage.
        You have tools available to add, update, or retrieve todos from the pipeline.
        You can also look up weather and query financial data.
        You can search flights and display rich A2UI cards (via search_flights tool).
        You can generate dynamic A2UI dashboards from conversation context (via generate_a2ui tool).

        When discussing sales todos, ALWAYS use the get_sales_todos tool to see the current list
        before mentioning, updating, or discussing todos with the user.
    """).strip(),
)

# =====
# Tools
# =====
@agent.tool
def get_weather(ctx: RunContext[StateDeps[SalesTodosState]], location: str) -> str:
    """Get the weather for a given location. Ensure location is fully spelled out."""
    return json.dumps(get_weather_impl(location))

@agent.tool
def query_data(ctx: RunContext[StateDeps[SalesTodosState]], query: str) -> str:
    """Query financial database for chart data. Returns data suitable for pie or bar charts."""
    return json.dumps(query_data_impl(query))

@agent.tool
async def manage_sales_todos(
    ctx: RunContext[StateDeps[SalesTodosState]], todos: list[dict[str, Any]]
) -> StateSnapshotEvent:
    """Manage the sales pipeline. Pass the complete list of sales todos."""
    result = manage_sales_todos_impl(todos)
    ctx.deps.state.todos = result
    return StateSnapshotEvent(
        type=EventType.STATE_SNAPSHOT,
        snapshot=ctx.deps.state,
    )

@agent.tool
def get_sales_todos(ctx: RunContext[StateDeps[SalesTodosState]]) -> str:
    """Get the current list of sales pipeline todos."""
    return json.dumps(get_sales_todos_impl(ctx.deps.state.todos or None))

@agent.tool
def schedule_meeting(ctx: RunContext[StateDeps[SalesTodosState]], reason: str, duration_minutes: int = 30) -> str:
    """Schedule a meeting. The user will be asked to pick a time via the UI."""
    return json.dumps(schedule_meeting_impl(reason, duration_minutes))

@agent.tool
def search_flights(ctx: RunContext[StateDeps[SalesTodosState]], flights: list[dict[str, Any]]) -> str:
    """Search for flights and display the results as rich cards. Return exactly 2 flights.

    Each flight must have: airline, airlineLogo, flightNumber, origin, destination,
    date (short readable format like "Tue, Mar 18" -- use near-future dates),
    departureTime, arrivalTime, duration (e.g. "4h 25m"),
    status (e.g. "On Time" or "Delayed"),
    statusColor (hex color for status dot),
    price (e.g. "$289"), and currency (e.g. "USD").

    For airlineLogo use Google favicon API:
    https://www.google.com/s2/favicons?domain={airline_domain}&sz=128
    """
    result = search_flights_impl(flights)
    return json.dumps(result)

@agent.tool
def generate_a2ui(ctx: RunContext[StateDeps[SalesTodosState]]) -> str:
    """Generate dynamic A2UI components based on the conversation.

    A secondary LLM designs the UI schema and data. The result is
    returned as an a2ui_operations container for the middleware to detect.
    """
    from openai import OpenAI

    # Extract conversation messages from deps
    copilotkit_state = getattr(ctx.deps, "copilotkit", None)
    conversation_messages: list[dict] = []
    context_entries: list[dict] = []
    if copilotkit_state:
        if hasattr(copilotkit_state, "messages"):
            for msg in (copilotkit_state.messages or []):
                role = msg.role.value if hasattr(msg.role, "value") else str(msg.role)
                if role in ("user", "assistant"):
                    content = ""
                    if hasattr(msg, "content"):
                        if isinstance(msg.content, str):
                            content = msg.content
                        elif isinstance(msg.content, list):
                            parts = []
                            for part in msg.content:
                                if hasattr(part, "text"):
                                    parts.append(part.text)
                                elif isinstance(part, dict) and "text" in part:
                                    parts.append(part["text"])
                            content = "".join(parts)
                    if content:
                        conversation_messages.append({"role": role, "content": content})
        if hasattr(copilotkit_state, "context"):
            context_entries = copilotkit_state.context or []

    context_text = "\n\n".join(
        entry.get("value", "")
        for entry in context_entries
        if isinstance(entry, dict) and entry.get("value")
    )

    client = OpenAI()
    tool_schema = {
        "type": "function",
        "function": {
            "name": "render_a2ui",
            "description": "Render a dynamic A2UI v0.9 surface.",
            "parameters": {
                "type": "object",
                "properties": {
                    "surfaceId": {"type": "string"},
                    "catalogId": {"type": "string"},
                    "components": {"type": "array", "items": {"type": "object"}},
                    "data": {"type": "object"},
                },
                "required": ["surfaceId", "catalogId", "components"],
            },
        },
    }

    llm_messages: list[dict] = [
        {"role": "system", "content": context_text or "Generate a useful dashboard UI."},
    ]
    llm_messages.extend(conversation_messages)

    response = client.chat.completions.create(
        model="gpt-4.1",
        messages=llm_messages,
        tools=[tool_schema],
        tool_choice={"type": "function", "function": {"name": "render_a2ui"}},
    )

    if not response.choices[0].message.tool_calls:
        return json.dumps({"error": "LLM did not call render_a2ui"})

    tool_call = response.choices[0].message.tool_calls[0]
    args = json.loads(tool_call.function.arguments)
    result = build_a2ui_operations_from_tool_call(args)
    return json.dumps(result)

/**
 * Demonstration Catalog -- Component Definitions
 *
 * Platform-agnostic definitions: component names, props (Zod), descriptions.
 * This is the contract between the app and the AI agent. Agents receive these
 * definitions as context so they know what components are available.
 *
 * Renderers (React, React Native, etc.) import these definitions and provide
 * platform-specific implementations, type-checked against the Zod schemas.
 */

import { z } from "zod";

/**
 * Dynamic string: accepts either a literal string or a data-model path binding
 * like `{ path: "airline" }`. The GenericBinder resolves path bindings to the
 * actual value at render time.
 */
const DynString = z.union([z.string(), z.object({ path: z.string() })]);

/**
 * Shared action schema used by interactive components (Button, FlightCard).
 * The GenericBinder resolves `{ event }` objects to callable `() => void` at
 * render time.
 */
const ActionSchema = z
  .union([
    z.object({
      event: z.object({
        name: z.string(),
        context: z.record(z.any()).optional(),
      }),
    }),
    z.null(),
  ])
  .optional();

export const demonstrationCatalogDefinitions = {
  Title: {
    description: "A heading. Use for section titles and page headers.",
    props: z.object({
      text: z.string(),
      level: z.string().optional(),
    }),
  },

  // Text: removed -- the basic catalog's Text uses DynamicStringSchema
  // which supports path bindings (e.g. { path: "flights[*].airline" }).
  // Overriding it with z.string() breaks fixed-schema data binding.

  Row: {
    description: "Horizontal layout container.",
    props: z.object({
      gap: z.number().optional(),
      align: z.string().optional(),
      justify: z.string().optional(),
      // Union with { componentId, path } so GenericBinder treats this as
      // STRUCTURAL and resolves template children from the data model.
      children: z.union([
        z.array(z.string()),
        z.object({ componentId: z.string(), path: z.string() }),
      ]),
    }),
  },

  Column: {
    description: "Vertical layout container.",
    props: z.object({
      gap: z.number().optional(),
      align: z.string().optional(),
      // Same union as Row -- required for template children support.
      children: z.union([
        z.array(z.string()),
        z.object({ componentId: z.string(), path: z.string() }),
      ]),
    }),
  },

  DashboardCard: {
    description:
